// ExtractAllTags retrieves all unique tags from projects for filtering
func ExtractAllTags(projects []models.Project) []string {
	tagMap := make(map[string]bool)
	for _, proj := range projects {
		for _, tag := range proj.Tags {
			tagMap[tag] = true
		}
	}
	tags := []string{"All"}
	for tag := range tagMap {
		tags = append(tags, tag)
	}
	return tags
}

